#[test]
fn test_http_error_snapshots() {
    let formatter = ErrorFormatter::new(OutputMode::Plain);

    let err_404 = HttpErrorInfo::new(404, "User not found")
        .path("/api/users/999")
        .method("GET");
    assert_snapshot!("http_error_404", formatter.format_http_error(&err_404).plain);

    let err_500 = HttpErrorInfo::new(500, "Database connection failed")
        .code("DB_ERROR")
        .path("/api/users")
        .method("POST");
    assert_snapshot!("http_error_500", formatter.format_http_error(&err_500).plain);
}
